import{_ as t,o as n,c as a,a2 as r}from"./chunks/framework.DTa47_fH.js";const c=JSON.parse('{"title":"Wie SWAO funktioniert","description":"","frontmatter":{},"headers":[],"relativePath":"de/how-it-works.md","filePath":"de/how-it-works.md"}'),i={name:"de/how-it-works.md"};function s(d,e,o,l,h,u){return n(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="wie-swao-funktioniert" tabindex="-1">Wie SWAO funktioniert <a class="header-anchor" href="#wie-swao-funktioniert" aria-label="Permalink to &quot;Wie SWAO funktioniert&quot;">​</a></h1><p>SWAO analysiert eine Cloud-Anwendung und erstellt in einem einzigen Befehl -- oder über die geführte Terminaloberfläche -- einen audit-konformen Bewertungsbericht. Keine externen Dienste, keine Datenuploads, kein Call-home.</p><hr><h2 id="die-gefuhrte-oberflache-tui" tabindex="-1">Die geführte Oberfläche (TUI) <a class="header-anchor" href="#die-gefuhrte-oberflache-tui" aria-label="Permalink to &quot;Die geführte Oberfläche (TUI)&quot;">​</a></h2><p>Wenn Sie <code>swao</code> ohne Argumente ausführen, öffnet sich die <strong>Terminaloberfläche</strong>.</p><h3 id="hauptmenu" tabindex="-1">Hauptmenü <a class="header-anchor" href="#hauptmenu" aria-label="Permalink to &quot;Hauptmenü&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SWAO -- Sovereign Workload Assessment and Onboarding</span></span>
<span class="line"><span>Community  v0.4.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1  Workspace Setup       Init + LLM + Zugangsdaten-Assistent</span></span>
<span class="line"><span>  2  Health Check          swao doctor</span></span>
<span class="line"><span>  3  Run Assessment        Anwendung / Audit / Landing Zone + mehr</span></span>
<span class="line"><span>  4  Generate Report       swao report (Text / PDF)</span></span>
<span class="line"><span>  5  Publish HTML          swao publish -- eigenständige HTML-Datei</span></span>
<span class="line"><span>  6  Export BI             Sternschema / PowerBI / Tableau</span></span>
<span class="line"><span>  7  Portfolio Operations  Multi-App-Aggregation (Premium)</span></span>
<span class="line"><span>  8  Generate TF Modules   swao generate-tf</span></span>
<span class="line"><span>  9  Tools                 Linsen / Lizenz / Zugangsdaten / Hilfe</span></span>
<span class="line"><span>  0  Exit</span></span></code></pre></div><blockquote><p>Siehe auch: <a href="/samples/#sample-10">Beispielgalerie -- TUI-Hauptmenü</a></p></blockquote><h3 id="workspace-setup-assistent" tabindex="-1">Workspace-Setup-Assistent <a class="header-anchor" href="#workspace-setup-assistent" aria-label="Permalink to &quot;Workspace-Setup-Assistent&quot;">​</a></h3><p>Wählen Sie <strong>1. Workspace Setup</strong>. Der Assistent stellt vier Fragen:</p><ol><li><strong>Workspace-Name</strong> -- Bezeichner für den Engagement-Ordner.</li><li><strong>Anwendungsname</strong> -- der zu bewertende Workload.</li><li><strong>Compliance-Rahmenwerke</strong> -- DSGVO ist vorausgewählt. Neun Community-Rahmenwerke verfügbar (DSGVO, KI 10 Säule, COBIT 5, NIST SP 800-66 R2, ISO 27001, PCI DSS, SOC 2, BSI C5, DORA).</li><li><strong>LLM-Anbieter</strong> -- Anthropic Claude, OpenAI, Ollama oder deterministischer Stub.</li></ol><h3 id="health-check-systemprufung" tabindex="-1">Health Check (Systemprüfung) <a class="header-anchor" href="#health-check-systemprufung" aria-label="Permalink to &quot;Health Check (Systemprüfung)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Prüfung</th><th>Was geprüft wird</th></tr></thead><tbody><tr><td>Lizenz</td><td>Edition erkannt und gültig</td></tr><tr><td>Playwright</td><td>Bereitschaft für dynamische Analyse</td></tr><tr><td>MCP</td><td>Model-Context-Protocol-Konfiguration</td></tr><tr><td>Compliance-Kataloge</td><td>Rahmenwerk-Dateien vorhanden</td></tr><tr><td>Import-Vorlagen</td><td>Einlese-Ordnerstruktur</td></tr><tr><td>Nachvollziehbarkeit</td><td>Audit-konforme Signalfelder aktiviert</td></tr><tr><td>BI-Exportpaket</td><td>Integrität des letzten Exports</td></tr></tbody></table><blockquote><p>Siehe auch: <a href="/samples/#sample-12">Beispielgalerie -- Health Check</a></p></blockquote><h3 id="bewertung-durchfuhren" tabindex="-1">Bewertung durchführen <a class="header-anchor" href="#bewertung-durchfuhren" aria-label="Permalink to &quot;Bewertung durchführen&quot;">​</a></h3><p>Wählen Sie <strong>3. Run Assessment</strong>, dann den Bewertungstyp:</p><table tabindex="0"><thead><tr><th>Option</th><th>Was es macht</th></tr></thead><tbody><tr><td>Anwendungsbewertung</td><td>Analysiert Ihren Quellcode</td></tr><tr><td>Landing-Zone-Bewertung</td><td>Prüft Ihre Cloud-Infrastruktur</td></tr><tr><td>Audit-Bewertung</td><td>Demnächst</td></tr><tr><td>LLM-Bewertung</td><td>Demnächst</td></tr><tr><td>Hybrid-Bewertung</td><td>Demnächst</td></tr></tbody></table><hr><h2 id="die-bewertungs-pipeline" tabindex="-1">Die Bewertungs-Pipeline <a class="header-anchor" href="#die-bewertungs-pipeline" aria-label="Permalink to &quot;Die Bewertungs-Pipeline {#die-bewertungs-pipeline}&quot;">​</a></h2><p>Eine <strong>Anwendungsbewertung</strong> führt bis zu 14 Analysedurchläufe durch.</p><table tabindex="0"><thead><tr><th>Durchlauf</th><th>Was er macht</th></tr></thead><tbody><tr><td>1. Inventar</td><td>Sprachen, Frameworks, Abhängigkeiten</td></tr><tr><td>2. Zustandsanalyse</td><td>Datenbanken, Session-Speicher, Caches</td></tr><tr><td>3. Datenklassifizierung</td><td>PII-Felder, Residenzmarkierungen</td></tr><tr><td>4. Kontexteinlese</td><td>CMDB, Workshop-Protokolle, Architekturdokumente</td></tr><tr><td>5. SBOM</td><td>Software-Stückliste mit Lizenzklassifizierung</td></tr><tr><td>6. Twelve-Factor</td><td>Cloud-Bereitschaft nach 12-Faktor-Standard</td></tr><tr><td>7. Ausgangsanalyse</td><td>Ausgehende Verbindungen, Drittanbieter-Transfers</td></tr><tr><td>8. Kryptographie</td><td>Hashing, TLS, Geheimnisbehandlung</td></tr><tr><td>9. Migrationssynthese</td><td>7R-Urteil</td></tr><tr><td>10. Compliance-Bewertung</td><td>Zuordnung zu aktiven Rahmenwerken</td></tr><tr><td>11. Landing-Zone-Bereitschaft</td><td>Fit für Cloud-Landing-Zone</td></tr><tr><td>12. Sicherheitspostur</td><td>Häufige Verwundbarkeitsmuster</td></tr><tr><td>13. Dynamische Analyse</td><td>Browser-Crawl für UI-Oberfläche</td></tr><tr><td>14. Evidenzgalerie</td><td>Screenshots und Artefakte</td></tr></tbody></table><hr><h2 id="die-html-veroeffentlichung" tabindex="-1">Die HTML-Veröffentlichung <a class="header-anchor" href="#die-html-veroeffentlichung" aria-label="Permalink to &quot;Die HTML-Veröffentlichung {#die-html-veroeffentlichung}&quot;">​</a></h2><p>SWAO erstellt eine <strong>eigenständige HTML-Datei</strong> -- offline nutzbar, per E-Mail versendbar.</p><p>Enthält:</p><ul><li><strong>Führungsansicht</strong> -- 7R-Urteil, Abdeckungspunktzahl, wichtigste Risiken.</li><li><strong>Fachansicht</strong> -- alle Signale mit Ableitung und Evidenzlinks.</li><li><strong>Compliance-Ansicht</strong> -- rahmenwerkspezifische Kontrolltabelle.</li><li><strong>Prüferansicht</strong> -- Prüfprotokoll mit Zeitstempel und Bewerteridentität.</li><li><strong>Evidenzgalerie</strong> -- Screenshots und Artefakte.</li><li><strong>Laufprotokoll</strong> -- Dauer, LLM-Kosten, Durchlauf-Aufschlüsselung.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">swao</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meine-app</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Öffnet: wsp/publications/latest/index.html</span></span></code></pre></div><hr><h2 id="mcp-integration" tabindex="-1">MCP-Integration <a class="header-anchor" href="#mcp-integration" aria-label="Permalink to &quot;MCP-Integration {#mcp-integration}&quot;">​</a></h2><p>SWAO verbindet sich über das <strong>Model Context Protocol (MCP)</strong> mit <strong>Claude AI</strong>.</p><p>Beispielfragen:</p><ul><li>&quot;Was sind die wichtigsten Compliance-Lücken?&quot;</li><li>&quot;Fassen Sie die Landing-Zone-Erkenntnisse zusammen.&quot;</li><li>&quot;Was ist das 7R-Migrationsurteil?&quot;</li></ul><h3 id="verbindung-herstellen" tabindex="-1">Verbindung herstellen <a class="header-anchor" href="#verbindung-herstellen" aria-label="Permalink to &quot;Verbindung herstellen&quot;">​</a></h3><ol><li><code>swao doctor</code> (oder <strong>2. Health Check</strong> im Hauptmenü) -- MCP-Prüfung zeigt den Serverpfad.</li><li>Claude Desktop: Einstellungen &gt; Entwickler &gt; MCP-Server &gt; Hinzufügen.</li><li>Claude Desktop neu starten.</li></ol><table tabindex="0"><thead><tr><th>Tool</th><th>Was es macht</th></tr></thead><tbody><tr><td><code>swao_assess</code></td><td>Neue Bewertung auslösen</td></tr><tr><td><code>swao_report</code></td><td>Zusammenfassung der letzten Bewertung</td></tr><tr><td><code>swao_signal_detail</code></td><td>Signal nach ID nachschlagen</td></tr><tr><td><code>swao_compliance_status</code></td><td>Compliance-Ergebnisse abfragen</td></tr><tr><td><code>swao_lz_fit</code></td><td>Landing-Zone-Fit/Gap abrufen</td></tr><tr><td><code>swao_run_history</code></td><td>Letzte Läufe auflisten</td></tr></tbody></table><hr><h2 id="powerbi-dashboards" tabindex="-1">PowerBI-Dashboards <a class="header-anchor" href="#powerbi-dashboards" aria-label="Permalink to &quot;PowerBI-Dashboards {#powerbi-dashboards}&quot;">​</a></h2><p>Vorgefertigte Vorlagen in Ihrem Workspace unter <code>wsp/templates/powerbi/</code>:</p><table tabindex="0"><thead><tr><th>Vorlage</th><th>Edition</th><th>Seiten</th></tr></thead><tbody><tr><td><code>swao-report.pbit</code></td><td>Consultant + Enterprise</td><td>Übersicht, Compliance, Signale, Risiken, Prüfer, Laufstatistiken</td></tr><tr><td><code>swao-portfolio.pbit</code></td><td>Enterprise</td><td>Portfolio-Übersicht, Heatmap, Compliance, Risiko &amp; 7R, Wellensequenzierung</td></tr></tbody></table><p>Öffnen Sie die <code>.pbit</code>-Datei, setzen Sie <code>SWAOExportPath</code> auf den <code>star/</code>-Ordner, klicken Sie <strong>Laden</strong>.</p><hr><h2 id="was-auf-ihrem-rechner-bleibt" tabindex="-1">Was auf Ihrem Rechner bleibt <a class="header-anchor" href="#was-auf-ihrem-rechner-bleibt" aria-label="Permalink to &quot;Was auf Ihrem Rechner bleibt&quot;">​</a></h2><ul><li>Keine Telemetrie. Keine Nutzungsdaten werden gesendet.</li><li>Kein gehosteter Endpunkt. Die Engine läuft lokal.</li><li>Kein Call-home. Das Binary prüft nicht auf Updates.</li><li>LLM-Aufrufe gehen direkt an Ihren konfigurierten Anbieter.</li><li>HTML-Veröffentlichung, BI-Export und PowerBI-Dashboard sind lokale Dateien.</li></ul>`,43)])])}const g=t(i,[["render",s]]);export{c as __pageData,g as default};
